import{_ as t,o,c as u,ag as q}from"./chunks/framework.-7YpjpW6.js";const i=JSON.parse('{"title":"第三章","description":"","frontmatter":{},"headers":[],"relativePath":"安乐回响-AI/3.md","filePath":"安乐回响-AI/3.md","lastUpdated":1776953967000}'),a={name:"安乐回响-AI/3.md"};function e(r,p,_,s,n,d){return o(),u("div",null,[...p[0]||(p[0]=[q('<h1 id="第三章" tabindex="-1">第三章 <a class="header-anchor" href="#第三章" aria-label="Permalink to &quot;第三章&quot;">​</a></h1><p>第二天上午，苏寒刚坐下，终端弹出会议邀请。</p><p>是行动组组长发的。</p><p>他没有多想，带着资料进了会议室。</p><p>组长已经在里面，正在倒咖啡。</p><p>&quot;昨天那个上报，高层看到了。&quot;他说得很随意，&quot;准备一下，简单过一遍。&quot;</p><p>会议很快接通。</p><p>接入人数比预期多。</p><p>除了行动组和技术部，还有合规、法务，以及几个没有标明具体部门的高权限账号。</p><hr><p>苏寒按既定结构，逐一详细汇报。</p><p>线索来源、传播路径、技术特征、风险评估。</p><p>汇报结束后，提问环节持续了比预期更久。</p><p>问题集中在两个方向：</p><p>&quot;信息是如何获取的？&quot;</p><p>&quot;是否存在非授权接触？&quot;</p><p>没有人讨论网站本身。</p><p>会议结束时，没有结论。</p><p>只有一句标准回复：&quot;材料已收录，后续统一处理。&quot;</p><p>屏幕关闭。</p><p>房间里安静了一会儿。</p><p>组长把电脑合上，说了一句：&quot;这事，级别不低。&quot;</p><hr><p>下午，苏寒再次收到会议通知。</p><p>这一次，没有视频接入。</p><p>内部会议室。他推门进去时，组长正在和人说话。是他们的HR。</p><p>桌面上没有任何纸质材料。只有一台打开的终端。</p><p>HR先开口：&quot;上午的材料，高层已经审阅。&quot;</p><p>&quot;结论是，你的工作没有问题。&quot;</p><p>她停顿了一下。</p><p>&quot;公司决定对你进行一次专项奖励。&quot;</p><p>她把屏幕转过来。</p><p>一份标准格式的通知：绩效加分，一次性奖金，七天带薪休假。</p><p>以及一条附加条款：</p><p>&quot;休假期间，相关工作设备暂由公司统一保管，用于资料复核。&quot;</p><p>措辞很规范。没有可以质疑的地方。</p><hr><p>苏寒看完，没有立即说话。</p><p>思考了一会儿，他问：&quot;复核范围包括哪些内容？&quot;</p><p>HR没有看他，只是把页面往下滑了一点。</p><p>&quot;与你本次上报相关的全部原始数据，以及必要的操作记录。&quot;</p><p>她停了一下，补了一句：&quot;这是标准流程。&quot;</p><p>苏寒点了点头。&quot;那后续调查？&quot;</p><p>HR终于抬头看了他一眼。</p><p>&quot;相关事项已经转入专项处理。&quot;</p><p>&quot;你这边的任务已经完成。接下来，建议你专注本职工作。&quot;</p><p>房间里没有其他声音。</p><p>空调的出风口在持续运转。</p><p>苏寒没有再追问。</p><p>他知道，这已经是边界。</p><p>&quot;专项&quot;，也没有说明由谁负责。</p><hr><p>从会议室出来，走廊一如既往地安静。</p><p>苏寒回到工位。</p><p>终端还亮着，停留在他上午的汇报页面。</p><p>只是屏幕上已经弹出提示：</p><p>&quot;设备访问权限已移交。&quot;</p><p>他把终端合上。</p><p>动作很轻。</p><p>像是在结束一项已经完成的任务。</p><p>设备还在他手里。</p><p>但已经不再对他开放。</p><hr><p>苏寒坐在工位上，盯着黑掉的屏幕。</p><p>他忽然想起一件事。</p><p>那个二维码，他只上报了链接地址。</p><p>但他没有上报的是——他在沙盒里留了一个备份。</p><p>一个完整的网站镜像。</p><p>包括那个线下交流会的时间和地点。</p><p>三天后。</p><p>市中心某商圈。</p><p>他看了一眼日历。</p><p>还有两天。</p>',73)])])}const l=t(a,[["render",e]]);export{i as __pageData,l as default};
